package store

import "context"

// Record is a single stored entry.
type Record struct {
	ID    string
	Value []byte
}

// Shard is one partition of the record store that can be scanned for a key.
type Shard interface {
	Lookup(ctx context.Context, key string) (*Record, bool)
}

// Store fans a lookup out across every shard and returns the first hit.
type Store struct {
	shards []Shard
}

// Find queries all shards concurrently and returns the first matching record.
// The first shard to report a hit wins; the remaining lookups are abandoned.
func (s *Store) Find(ctx context.Context, key string) (*Record, error) {
	results := make(chan *Record, len(s.shards))
	for _, shard := range s.shards {
		go func(sh Shard) {
			if rec, ok := sh.Lookup(ctx, key); ok {
				results <- rec
			}
		}(shard)
	}

	select {
	case rec := <-results:
		return rec, nil
	case <-ctx.Done():
		return nil, ctx.Err()
	}
}

